# ====================================================================
# Reading cached full MIF with selected REMIND-MAgPIE data
inbigmif <- readRDS("inbigmif.rds")

# inbigmif %>% select%>% select(variable) %>%

# Adding extended scenario info columns
allscens <- inbigmif %>%
    select(scenario) %>%
    unique()
sceninfo <- allscens %>%
    separate(scenario, c("vtag", "lsm", "ssp", "policy"), sep = "-", remove = F) %>%
    select(-vtag) %>%
    mutate(cbudget = ifelse(str_detect(policy, "Budg"), str_extract(policy, "[0-9][0-9][0-9]"), "NA")) %>%
    mutate(cbudget = as.numeric(cbudget))

bigmif <- inbigmif %>%
    left_join(sceninfo)

# Adding cumulative variables
cumvars <- c(
    "Emi|CO2",
    "Emi|CO2|+|Land-Use Change"
)
cummif <- bigmif %>%
    # filter(variable %in% cumvars) %>%
    group_by_at(vars(-period, -value)) %>%
    arrange(period, .by_group = T) %>%
    mutate(dt = period - lag(period)) %>%
    filter(period >= 2020) %>%
    mutate(value = cumsum(value * dt)) %>%
    mutate(variable = paste0(variable, "|Cum")) %>%
    select(-dt) %>%
    ungroup()
bigmif <- bind_rows(bigmif, cummif)

# ====================================================================
# Append climate MIF in a separate mixbigmif variable
inclimmif <- readRDS(climfname)

# Add an average of all climate outcomes across DVGM parametrizations
# TODO: Replace this with specific AR6-only MAGICC runs
inclimmif <- inclimmif %>%
  group_by(scenario, variable, period, quant) %>%
  summarise(value = mean(value, na.rm = TRUE)) %>%
  ungroup() %>%
  mutate(model = "Average_AllDVGMs") %>%
  bind_rows(inclimmif,.)


mixbigmif <- inclimmif %>%
    mutate(variable = paste0(variable, "|", quant)) %>%
    mutate(region = "GLO") %>%
    select(-quant) %>%
    left_join(sceninfo) %>%
    bind_rows(bigmif, .)
mixbigmif %>% select(variable) %>% unique %>% write.csv("varlist_mixbigmif.csv", row.names=F)

